import{_ as n,o as s,c as a,e}from"./app-DD1UE2QT.js";const t={},o=e(`<h1 id="collection-builders" tabindex="-1"><a class="header-anchor" href="#collection-builders"><span>Collection Builders</span></a></h1><p>Robo provides task collections as a means of making error detection and recovery easier. When Robo tasks are added to a collection, their execution is deferred until the <code>$collection-&gt;run()</code> method is called. If one of the tasks fail, then the operation will be aborted; rollback tasks may also be defined to restore the system to its original condition.</p><p>When using collections, a Robo script will go through three phases:</p><ol><li>Determine which tasks will need to be run, and create a task builder.</li></ol><ul><li>Assign values to variables.</li><li>Do not alter the state of the system.</li></ul><ol start="2"><li>Create the necessary tasks via the task builder.</li></ol><ul><li>Use variables calculated in the first phase in task parameters.</li></ul><ol start="3"><li>Run the tasks via the <code>run()</code> method.</li></ol><ul><li>Check and report errors once after <code>run()</code> returns.</li></ul><p>Following this pattern will keep your code linear and easy to understand.</p><h2 id="collections-api" tabindex="-1"><a class="header-anchor" href="#collections-api"><span>Collections API</span></a></h2><p>Collections are made up of a combination of tasks and/or <code>callable</code> functions / method pointers, such as:</p><ul><li>A task (implements TaskInterface)</li><li>A function name (string)</li><li>A closure (inline function)</li><li>A method reference (array with object and method name)</li></ul><p>Examples of adding different kinds of tasks to a collection are provided below.</p><h3 id="taskinterface-objects" tabindex="-1"><a class="header-anchor" href="#taskinterface-objects"><span>TaskInterface Objects</span></a></h3><div class="language-php line-numbers-mode" data-ext="php" data-title="php"><pre class="language-php"><code><span class="token php language-php"><span class="token delimiter important">&lt;?php</span>
  <span class="token variable">$collection</span><span class="token operator">-&gt;</span><span class="token function">add</span><span class="token punctuation">(</span>
    <span class="token variable">$this</span><span class="token operator">-&gt;</span><span class="token function">taskExec</span><span class="token punctuation">(</span><span class="token string single-quoted-string">&#39;ls&#39;</span><span class="token punctuation">)</span>
  <span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token delimiter important">?&gt;</span></span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="functions" tabindex="-1"><a class="header-anchor" href="#functions"><span>Functions</span></a></h3><div class="language-php line-numbers-mode" data-ext="php" data-title="php"><pre class="language-php"><code><span class="token php language-php"><span class="token delimiter important">&lt;?php</span>
  <span class="token variable">$collection</span><span class="token operator">-&gt;</span><span class="token function">addCode</span><span class="token punctuation">(</span><span class="token string single-quoted-string">&#39;mytaskfunction&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token delimiter important">?&gt;</span></span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="closures" tabindex="-1"><a class="header-anchor" href="#closures"><span>Closures</span></a></h3><div class="language-php line-numbers-mode" data-ext="php" data-title="php"><pre class="language-php"><code><span class="token php language-php"><span class="token delimiter important">&lt;?php</span>
  <span class="token variable">$collection</span><span class="token operator">-&gt;</span><span class="token function">addCode</span><span class="token punctuation">(</span>
    <span class="token keyword">function</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token keyword">use</span> <span class="token punctuation">(</span><span class="token variable">$work</span><span class="token punctuation">)</span>
    <span class="token punctuation">{</span>
      <span class="token comment">// do something with $work      </span>
    <span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token delimiter important">?&gt;</span></span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="methods" tabindex="-1"><a class="header-anchor" href="#methods"><span>Methods</span></a></h3><div class="language-php line-numbers-mode" data-ext="php" data-title="php"><pre class="language-php"><code><span class="token php language-php"><span class="token delimiter important">&lt;?php</span>
  <span class="token variable">$collection</span><span class="token operator">-&gt;</span><span class="token function">addCode</span><span class="token punctuation">(</span><span class="token punctuation">[</span><span class="token variable">$myobject</span><span class="token punctuation">,</span> <span class="token string single-quoted-string">&#39;mymethod&#39;</span><span class="token punctuation">]</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token delimiter important">?&gt;</span></span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="using-a-collection-builder" tabindex="-1"><a class="header-anchor" href="#using-a-collection-builder"><span>Using a Collection Builder</span></a></h2><p>To manage a collection of tasks, use a collection builder. Collection builders allow tasks to be created via chained methods. All of the tasks created by the same builder are added to a collection; when the <code>run()</code> method is called, all of the tasks in the collection run.</p><p>The &#39;publish&#39; command from Robo&#39;s own RoboFile is shown below. It uses a collection builder to run some git and filesystem operations. The &quot;completion&quot; tasks are run after all other tasks complete, or during rollback processing when an operation fails.</p><div class="language-php line-numbers-mode" data-ext="php" data-title="php"><pre class="language-php"><code><span class="token php language-php"><span class="token delimiter important">&lt;?php</span>
<span class="token keyword">class</span> <span class="token class-name-definition class-name">RoboFile</span> <span class="token keyword">extends</span> <span class="token class-name class-name-fully-qualified"><span class="token punctuation">\\</span>Robo<span class="token punctuation">\\</span>Tasks</span>
<span class="token punctuation">{</span>
    <span class="token keyword">public</span> <span class="token keyword">function</span> <span class="token function-definition function">publish</span><span class="token punctuation">(</span><span class="token class-name type-declaration">ConsoleIO</span> <span class="token variable">$io</span><span class="token punctuation">)</span>
    <span class="token punctuation">{</span>
        <span class="token variable">$current_branch</span> <span class="token operator">=</span> <span class="token function">exec</span><span class="token punctuation">(</span><span class="token string single-quoted-string">&#39;git rev-parse --abbrev-ref HEAD&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>

        <span class="token variable">$collection</span> <span class="token operator">=</span> <span class="token variable">$this</span><span class="token operator">-&gt;</span><span class="token function">collectionBuilder</span><span class="token punctuation">(</span><span class="token variable">$io</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
        <span class="token variable">$collection</span><span class="token operator">-&gt;</span><span class="token function">taskGitStack</span><span class="token punctuation">(</span><span class="token punctuation">)</span>
            <span class="token operator">-&gt;</span><span class="token function">checkout</span><span class="token punctuation">(</span><span class="token string single-quoted-string">&#39;site&#39;</span><span class="token punctuation">)</span>
            <span class="token operator">-&gt;</span><span class="token function">merge</span><span class="token punctuation">(</span><span class="token string single-quoted-string">&#39;master&#39;</span><span class="token punctuation">)</span>
        <span class="token operator">-&gt;</span><span class="token function">completion</span><span class="token punctuation">(</span><span class="token variable">$this</span><span class="token operator">-&gt;</span><span class="token function">taskGitStack</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token operator">-&gt;</span><span class="token function">checkout</span><span class="token punctuation">(</span><span class="token variable">$current_branch</span><span class="token punctuation">)</span><span class="token punctuation">)</span>
        <span class="token operator">-&gt;</span><span class="token function">taskFilesystemStack</span><span class="token punctuation">(</span><span class="token punctuation">)</span>
            <span class="token operator">-&gt;</span><span class="token function">copy</span><span class="token punctuation">(</span><span class="token string single-quoted-string">&#39;CHANGELOG.md&#39;</span><span class="token punctuation">,</span> <span class="token string single-quoted-string">&#39;docs/changelog.md&#39;</span><span class="token punctuation">)</span>
        <span class="token operator">-&gt;</span><span class="token function">completion</span><span class="token punctuation">(</span><span class="token variable">$this</span><span class="token operator">-&gt;</span><span class="token function">taskFilesystemStack</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token operator">-&gt;</span><span class="token function">remove</span><span class="token punctuation">(</span><span class="token string single-quoted-string">&#39;docs/changelog.md&#39;</span><span class="token punctuation">)</span><span class="token punctuation">)</span>
        <span class="token operator">-&gt;</span><span class="token function">taskExec</span><span class="token punctuation">(</span><span class="token string single-quoted-string">&#39;mkdocs gh-deploy&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>

        <span class="token keyword">return</span> <span class="token variable">$collection</span><span class="token punctuation">;</span>
    <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
<span class="token delimiter important">?&gt;</span></span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>The example above also adds a couple of tasks as &quot;completions&quot;; these are run when the collection completes execution, as explained below.</p><h2 id="rollbacks-and-completions" tabindex="-1"><a class="header-anchor" href="#rollbacks-and-completions"><span>Rollbacks and Completions</span></a></h2><p>Robo also provides rollbacks and completions, special tasks that are eligible to run only if all of the tasks added to the collection before them succeed. The section below explains the circumstances under which these tasks will run.</p><h3 id="completion-tasks" tabindex="-1"><a class="header-anchor" href="#completion-tasks"><span>Completion Tasks</span></a></h3><p>Completions run whenever their collection completes or fails, but only if all of the tasks that come before it succeed. An example of this is shown in the first example above. A filesystem stack task copies CHANDELOG.md to docs/changelog.md; after this task is added to the collection, another filesystem stack task is added as a completion to delete docs/changelog.md. This is done because docs/changelog.md is only intended to exist long enough to be used by the <code>mkdocs</code> task, which is added later.</p><h3 id="rollback-tasks" tabindex="-1"><a class="header-anchor" href="#rollback-tasks"><span>Rollback Tasks</span></a></h3><p>In addition to completions, Robo also supports rollbacks. Rollback tasks can be used to clean up after failures, so the state of the system does not change when execution is interrupted by an error. A rollback task is executed if all of the tasks that come before it succeed, and at least one of the tasks that come after it fails. If all tasks succeed, then no rollback tasks are executed.</p><h3 id="rollback-and-completion-methods" tabindex="-1"><a class="header-anchor" href="#rollback-and-completion-methods"><span>Rollback and Completion Methods</span></a></h3><p>Any task may also implement \\Robo\\Contract\\RollbackInterface; if this is done, then its <code>rollback()</code> method will be called if the task is <code>run()</code> on a collection that later fails.</p><p>Use <code>addAsCompletion($collection)</code> in place of <code>addAsRollback($collection)</code>, or implement \\Robo\\Contract\\CompletionInterface. Completions otherwise work exactly like rollbacks.</p><p>By default, rollbacks and completions tasks or callbacks continue even if errors occur. If you would like to explicitly cancel or abort the rollback or completion, you may throw the <code>\\Robo\\Exception\\AbortTasksException</code> exception.</p><h3 id="rollback-and-completion-callbacks" tabindex="-1"><a class="header-anchor" href="#rollback-and-completion-callbacks"><span>Rollback and Completion Callbacks</span></a></h3><p>You may also provide arbitrary methods as <code>callable</code>s to serve as rollback or completion functions, as shown below:</p><div class="language-php line-numbers-mode" data-ext="php" data-title="php"><pre class="language-php"><code><span class="token php language-php"><span class="token delimiter important">&lt;?php</span>
  <span class="token variable">$collection</span><span class="token operator">-&gt;</span><span class="token function">rollbackCode</span><span class="token punctuation">(</span><span class="token punctuation">[</span><span class="token variable">$myobject</span><span class="token punctuation">,</span> <span class="token string single-quoted-string">&#39;myrollback&#39;</span><span class="token punctuation">]</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
  <span class="token variable">$collection</span><span class="token operator">-&gt;</span><span class="token function">completionCode</span><span class="token punctuation">(</span><span class="token punctuation">[</span><span class="token variable">$myobject</span><span class="token punctuation">,</span> <span class="token string single-quoted-string">&#39;mycompletion&#39;</span><span class="token punctuation">]</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token delimiter important">?&gt;</span></span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="temporary-objects" tabindex="-1"><a class="header-anchor" href="#temporary-objects"><span>Temporary Objects</span></a></h2><p>Since the concept of temporary objects that are cleaned up on failure is a common pattern, Robo provides built-in support for them. Temporary directories and files are provided out of the box; other kinds of temporary objects can be easily created using the Temporary global collection.</p><h3 id="temporary-directories" tabindex="-1"><a class="header-anchor" href="#temporary-directories"><span>Temporary Directories</span></a></h3><p>It is recommended that operations that perform multiple filesystem operations should, whenever possible, do most of their work in a temporary directory. Temporary directories are created by <code>$this-&gt;taskTmpDir()</code>, and are automatically removed when the collection completes or rolls back. As an added convenience, the CollectionBuilder class has a <code>tmpDir()</code> method that creates a temporary directory via <code>taskTmpDir()</code>, and then returns the path to the temporary directory.</p><div class="language-php line-numbers-mode" data-ext="php" data-title="php"><pre class="language-php"><code><span class="token php language-php"><span class="token delimiter important">&lt;?php</span>
<span class="token keyword">class</span> <span class="token class-name-definition class-name">RoboFile</span> <span class="token keyword">extends</span> <span class="token class-name class-name-fully-qualified"><span class="token punctuation">\\</span>Robo<span class="token punctuation">\\</span>Tasks</span>
<span class="token punctuation">{</span>
    <span class="token keyword">function</span> <span class="token function-definition function">myOperation</span><span class="token punctuation">(</span><span class="token class-name type-declaration">ConsoleIO</span> <span class="token variable">$io</span><span class="token punctuation">)</span>
    <span class="token punctuation">{</span>
        <span class="token variable">$collection</span> <span class="token operator">=</span> <span class="token variable">$this</span><span class="token operator">-&gt;</span><span class="token function">collectionBuilder</span><span class="token punctuation">(</span><span class="token variable">$io</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
        
        <span class="token comment">// Create a temporary directory, and fetch its path.</span>
        <span class="token variable">$work</span> <span class="token operator">=</span> <span class="token variable">$collection</span><span class="token operator">-&gt;</span><span class="token function">tmpDir</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>

        <span class="token variable">$collection</span>
          <span class="token operator">-&gt;</span><span class="token function">taskWriteToFile</span><span class="token punctuation">(</span><span class="token string double-quoted-string">&quot;<span class="token interpolation"><span class="token variable">$work</span></span>/README.md&quot;</span><span class="token punctuation">)</span>
            <span class="token operator">-&gt;</span><span class="token function">line</span><span class="token punctuation">(</span><span class="token string single-quoted-string">&#39;-----&#39;</span><span class="token punctuation">)</span>
            <span class="token operator">-&gt;</span><span class="token function">line</span><span class="token punctuation">(</span><span class="token function">date</span><span class="token punctuation">(</span><span class="token string single-quoted-string">&#39;Y-m-d&#39;</span><span class="token punctuation">)</span><span class="token operator">.</span><span class="token string single-quoted-string">&#39; Generated file: do not edit.&#39;</span><span class="token punctuation">)</span>
            <span class="token operator">-&gt;</span><span class="token function">line</span><span class="token punctuation">(</span><span class="token string single-quoted-string">&#39;----&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
        
        <span class="token comment">// If all of the preceding tasks succeed, then rename the temporary </span>
        <span class="token comment">// directory to its final name.</span>
        <span class="token variable">$collection</span><span class="token operator">-&gt;</span><span class="token function">taskFilesystemStack</span><span class="token punctuation">(</span><span class="token punctuation">)</span>
          <span class="token operator">-&gt;</span><span class="token function">rename</span><span class="token punctuation">(</span><span class="token variable">$work</span><span class="token punctuation">,</span> <span class="token string single-quoted-string">&#39;destination&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
        
        <span class="token keyword">return</span> <span class="token variable">$collection</span><span class="token operator">-&gt;</span><span class="token function">run</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
    <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
<span class="token delimiter important">?&gt;</span></span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>In the previous example, the path to the temporary directory is stored in the variable <code>$work</code>, and is passed as needed to the parameters of the other tasks as they are added to the collection. After the task collection is run, the temporary directory will be automatically deleted. In the example above, the temporary directory is renamed by the last task in the collection. This allows the working directory to persist; the collection will still attempt to remove the working directory, but no errors will be thrown if it no longer exists in its original location. Following this pattern allows Robo scripts to easily and safely do work that cleans up after itself on failure, without introducing a lot of branching or additional error recovery code. This paradigm is common enough to warrant a shortcut method of accomplishing the same thing. The example below is identical to the one above, save for the fact that it uses the <code>workDir()</code> method instead of <code>tmpDir()</code>. <code>workDir()</code> renames the temporary directory to its final name if the collection completes; any directory that exists in the same location will be overwritten at that time, but will persist if the collection roles back.</p><div class="language-php line-numbers-mode" data-ext="php" data-title="php"><pre class="language-php"><code><span class="token php language-php"><span class="token delimiter important">&lt;?php</span>
<span class="token keyword">class</span> <span class="token class-name-definition class-name">RoboFile</span> <span class="token keyword">extends</span> <span class="token class-name class-name-fully-qualified"><span class="token punctuation">\\</span>Robo<span class="token punctuation">\\</span>Tasks</span>
<span class="token punctuation">{</span>
    <span class="token keyword">function</span> <span class="token function-definition function">myOperation</span><span class="token punctuation">(</span><span class="token class-name type-declaration">ConsoleIO</span> <span class="token variable">$io</span><span class="token punctuation">)</span>
    <span class="token punctuation">{</span>
        <span class="token variable">$collection</span> <span class="token operator">=</span> <span class="token variable">$this</span><span class="token operator">-&gt;</span><span class="token function">collectionBuilder</span><span class="token punctuation">(</span><span class="token variable">$io</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
        
        <span class="token comment">// Create a temporary directory, and fetch its path.</span>
        <span class="token comment">// If all of the tasks succeed, then rename the temporary directory</span>
        <span class="token comment">// to its final name.</span>
        <span class="token variable">$work</span> <span class="token operator">=</span> <span class="token variable">$collection</span><span class="token operator">-&gt;</span><span class="token function">workDir</span><span class="token punctuation">(</span><span class="token string single-quoted-string">&#39;destination&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>

        <span class="token variable">$collection</span>
          <span class="token operator">-&gt;</span><span class="token function">taskWriteToFile</span><span class="token punctuation">(</span><span class="token string double-quoted-string">&quot;<span class="token interpolation"><span class="token variable">$work</span></span>/README.md&quot;</span><span class="token punctuation">)</span>
            <span class="token operator">-&gt;</span><span class="token function">line</span><span class="token punctuation">(</span><span class="token string single-quoted-string">&#39;-----&#39;</span><span class="token punctuation">)</span>
            <span class="token operator">-&gt;</span><span class="token function">line</span><span class="token punctuation">(</span><span class="token function">date</span><span class="token punctuation">(</span><span class="token string single-quoted-string">&#39;Y-m-d&#39;</span><span class="token punctuation">)</span><span class="token operator">.</span><span class="token string single-quoted-string">&#39; Generated file: do not edit.&#39;</span><span class="token punctuation">)</span>
            <span class="token operator">-&gt;</span><span class="token function">line</span><span class="token punctuation">(</span><span class="token string single-quoted-string">&#39;----&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
        
        <span class="token keyword">return</span> <span class="token variable">$collection</span><span class="token operator">-&gt;</span><span class="token function">run</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
    <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
<span class="token delimiter important">?&gt;</span></span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Temporary directories may also be created via the shortcut <code>$this-&gt;_tmpDir();</code>. Temporary directories created in this way are deleted when the script terminates.</p><h3 id="temporary-files" tabindex="-1"><a class="header-anchor" href="#temporary-files"><span>Temporary Files</span></a></h3><p>Robo also provides an API for creating temporary files. They may be created via <code>$this-&gt;taskTmpFile()</code>; they are used exactly like <code>$this-&gt;taskWrite()</code>, except they are given a random name on creation, and are deleted when their collection completes. If they are not added to a collection, then they are deleted when the script terminates.</p><h3 id="the-temporary-global-collection" tabindex="-1"><a class="header-anchor" href="#the-temporary-global-collection"><span>The Temporary Global Collection</span></a></h3><p>Robo maintains a special collection called the Temporary global collection. This collection is used to keep track of temporary objects that are not part of any collection. For example, Robo temporary directories and temporary files are managed by the Temporary global collection. These temporary objects are cleaned up automatically when the script terminates.</p><p>It is easy to create your own temporary tasks that behave in the same way as the provided temporary directory and temporary file tasks. There are two steps required:</p><ul><li>Implement \\Robo\\Contract\\CompletionInterface</li><li>Wrap the task via Temporary::wrap()</li></ul><p>For example, the implementation of taskTmpFile() looks like this:</p><div class="language-php line-numbers-mode" data-ext="php" data-title="php"><pre class="language-php"><code><span class="token php language-php"><span class="token delimiter important">&lt;?php</span>
    <span class="token keyword">protected</span> <span class="token keyword">function</span> <span class="token function-definition function">taskTmpFile</span><span class="token punctuation">(</span><span class="token variable">$filename</span> <span class="token operator">=</span> <span class="token string single-quoted-string">&#39;tmp&#39;</span><span class="token punctuation">,</span> <span class="token variable">$extension</span> <span class="token operator">=</span> <span class="token string single-quoted-string">&#39;&#39;</span><span class="token punctuation">,</span> <span class="token variable">$baseDir</span> <span class="token operator">=</span> <span class="token string single-quoted-string">&#39;&#39;</span><span class="token punctuation">,</span> <span class="token variable">$includeRandomPart</span> <span class="token operator">=</span> <span class="token constant boolean">true</span><span class="token punctuation">)</span>
    <span class="token punctuation">{</span>
        <span class="token keyword">return</span> <span class="token class-name static-context">Temporary</span><span class="token operator">::</span><span class="token function">wrap</span><span class="token punctuation">(</span><span class="token keyword">new</span> <span class="token class-name">TmpFile</span><span class="token punctuation">(</span><span class="token variable">$filename</span><span class="token punctuation">,</span> <span class="token variable">$extension</span><span class="token punctuation">,</span> <span class="token variable">$baseDir</span><span class="token punctuation">,</span> <span class="token variable">$includeRandomPart</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
    <span class="token punctuation">}</span>
<span class="token delimiter important">?&gt;</span></span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>The <code>complete()</code> method of the task will be called once the Collection the temporary object is attached to finishes running. If the temporary is not added to a collection, then its <code>complete()</code> method will be called when the script terminates.</p><h2 id="chained-state" tabindex="-1"><a class="header-anchor" href="#chained-state"><span>Chained State</span></a></h2><p>When using a collection builder, it is possible to pass state from one task to another. State is generated during the <code>run()</code> method of each task, and returned in a <code>Robo\\Result</code> object. Each result has a &quot;message&quot; and a key/value data store that contains the task&#39;s state. This state can be made available to later tasks in the builder.</p><h3 id="implicitly-passing-state" tabindex="-1"><a class="header-anchor" href="#implicitly-passing-state"><span>Implicitly Passing State</span></a></h3><p>Sometimes it may be desirable to process the files produced by one task using a following task that alters the result.</p><p>For example, if you have one task that takes a set of source files and generates destination files, and another task that encrypts a set of files, you could encrypt the results from the first task by running both of the tasks independently:</p><div class="language-php line-numbers-mode" data-ext="php" data-title="php"><pre class="language-php"><code><span class="token php language-php"><span class="token delimiter important">&lt;?php</span>
    <span class="token variable">$result</span> <span class="token operator">=</span> <span class="token variable">$this</span><span class="token operator">-&gt;</span><span class="token function">taskGenerate</span><span class="token punctuation">(</span><span class="token punctuation">)</span>
        <span class="token operator">-&gt;</span><span class="token function">files</span><span class="token punctuation">(</span><span class="token variable">$sources</span><span class="token punctuation">)</span>
        <span class="token operator">-&gt;</span><span class="token function">run</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
    
    <span class="token variable">$result</span> <span class="token operator">=</span> <span class="token variable">$this</span><span class="token operator">-&gt;</span><span class="token function">taskEncrypt</span><span class="token punctuation">(</span><span class="token punctuation">)</span>
        <span class="token operator">-&gt;</span><span class="token function">files</span><span class="token punctuation">(</span><span class="token variable">$result</span><span class="token punctuation">[</span><span class="token string single-quoted-string">&#39;files&#39;</span><span class="token punctuation">]</span><span class="token punctuation">)</span>
        <span class="token operator">-&gt;</span><span class="token function">run</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token delimiter important">?&gt;</span></span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>If the Encrypt task implements <code>\\Robo\\State\\Consumer</code> and accepts &#39;files&#39; from the current state, then these tasks may be chained together as follows:</p><div class="language-php line-numbers-mode" data-ext="php" data-title="php"><pre class="language-php"><code><span class="token php language-php"><span class="token delimiter important">&lt;?php</span>
    <span class="token variable">$collection</span> <span class="token operator">=</span> <span class="token variable">$this</span><span class="token operator">-&gt;</span><span class="token function">collectionBuilder</span><span class="token punctuation">(</span><span class="token variable">$io</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
    <span class="token variable">$collection</span>
        <span class="token operator">-&gt;</span><span class="token function">taskGenerate</span><span class="token punctuation">(</span><span class="token punctuation">)</span>
            <span class="token operator">-&gt;</span><span class="token function">files</span><span class="token punctuation">(</span><span class="token variable">$sources</span><span class="token punctuation">)</span>
        <span class="token operator">-&gt;</span><span class="token function">taskEncrypt</span><span class="token punctuation">(</span><span class="token punctuation">)</span>
        <span class="token operator">-&gt;</span><span class="token function">run</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token delimiter important">?&gt;</span></span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Tasks that do not implement the <code>Consumer</code> interface may still be chained together by explicitly connecting the state from one task with the task configuration methods, as explained in the following section:</p><h3 id="explicitly-passing-state" tabindex="-1"><a class="header-anchor" href="#explicitly-passing-state"><span>Explicitly Passing State</span></a></h3><p>State from the key/value data store, if set, is automatically stored in the collection&#39;s state. The <code>storeState()</code> method can be used to store the result &quot;message&quot;.</p><p>To pass state from one task to another, the <code>deferTaskConfiguration()</code> method may be used. This method defers initialization until immediately before the task&#39;s <code>run()</code> method is called. It then calls a single named setter method, passing it the value of some state variable.</p><p>For example, the builder below will create a new directory named after the output of the <code>uname -n</code> command returned by taskExec. Note that it is necessary to call <code>printOutput(false)</code> in order to make the output of taskExec available to the state system.</p><div class="language-php line-numbers-mode" data-ext="php" data-title="php"><pre class="language-php"><code><span class="token php language-php"><span class="token delimiter important">&lt;?php</span>
    <span class="token variable">$this</span><span class="token operator">-&gt;</span><span class="token function">collectionBuilder</span><span class="token punctuation">(</span><span class="token variable">$io</span><span class="token punctuation">)</span>
        <span class="token operator">-&gt;</span><span class="token function">taskExec</span><span class="token punctuation">(</span><span class="token string single-quoted-string">&#39;uname -n&#39;</span><span class="token punctuation">)</span>
            <span class="token operator">-&gt;</span><span class="token function">printOutput</span><span class="token punctuation">(</span><span class="token constant boolean">false</span><span class="token punctuation">)</span>
            <span class="token operator">-&gt;</span><span class="token function">storeState</span><span class="token punctuation">(</span><span class="token string single-quoted-string">&#39;system-name&#39;</span><span class="token punctuation">)</span>
        <span class="token operator">-&gt;</span><span class="token function">taskFilesystemStack</span><span class="token punctuation">(</span><span class="token punctuation">)</span>
            <span class="token operator">-&gt;</span><span class="token function">deferTaskConfiguration</span><span class="token punctuation">(</span><span class="token string single-quoted-string">&#39;mkdir&#39;</span><span class="token punctuation">,</span> <span class="token string single-quoted-string">&#39;system-name&#39;</span><span class="token punctuation">)</span>
        <span class="token operator">-&gt;</span><span class="token function">run</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token delimiter important">?&gt;</span></span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>More complex task configuration may be done via the <code>defer()</code> method. <code>defer()</code> works like <code>deferTaskConfiguration()</code>, except that it will run an arbitrary <code>callable</code> immediately prior to the execution of the task. The example below works exactly the same as the previous example, but is implemented using <code>defer()</code> instead of <code>deferTaskConfiguration()</code>.</p><div class="language-php line-numbers-mode" data-ext="php" data-title="php"><pre class="language-php"><code><span class="token php language-php"><span class="token delimiter important">&lt;?php</span>
    <span class="token variable">$this</span><span class="token operator">-&gt;</span><span class="token function">collectionBuilder</span><span class="token punctuation">(</span><span class="token variable">$io</span><span class="token punctuation">)</span>
        <span class="token operator">-&gt;</span><span class="token function">taskExec</span><span class="token punctuation">(</span><span class="token string single-quoted-string">&#39;uname -n&#39;</span><span class="token punctuation">)</span>
            <span class="token operator">-&gt;</span><span class="token function">printOutput</span><span class="token punctuation">(</span><span class="token constant boolean">false</span><span class="token punctuation">)</span>
            <span class="token operator">-&gt;</span><span class="token function">storeState</span><span class="token punctuation">(</span><span class="token string single-quoted-string">&#39;system-name&#39;</span><span class="token punctuation">)</span>
        <span class="token operator">-&gt;</span><span class="token function">taskFilesystemStack</span><span class="token punctuation">(</span><span class="token punctuation">)</span>
            <span class="token operator">-&gt;</span><span class="token function">defer</span><span class="token punctuation">(</span>
                <span class="token keyword">function</span> <span class="token punctuation">(</span><span class="token variable">$task</span><span class="token punctuation">,</span> <span class="token variable">$state</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
                    <span class="token variable">$task</span><span class="token operator">-&gt;</span><span class="token function">mkdir</span><span class="token punctuation">(</span><span class="token variable">$state</span><span class="token punctuation">[</span><span class="token string single-quoted-string">&#39;system-name&#39;</span><span class="token punctuation">]</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
                <span class="token punctuation">}</span>
            <span class="token punctuation">)</span>
        <span class="token operator">-&gt;</span><span class="token function">run</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token delimiter important">?&gt;</span></span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>In general, it is preferable to collect all of the information needed first, and then use that data to configure the necessary tasks. For example, the previous example could be implemented more simply by calling <code>$system_name = exec(&#39;uname -n&#39;);</code> and <code>taskFilesystemStack-&gt;mkdir($system_name);</code>. Chained state can be helpful in instances where there is a more complex relationship between the tasks.</p><h2 id="named-tasks" tabindex="-1"><a class="header-anchor" href="#named-tasks"><span>Named Tasks</span></a></h2><p>It is also possible to provide names for the tasks added to a collection. This has two primary benefits:</p><ol><li>Any result data returned from a named task is stored in the Result object under the task name.</li><li>It is possible for other code to add more tasks before or after any named task.</li></ol><p>This feature is useful if you have functions that create task collections, and return them as a function results. The original caller can then use the <code>$collection-&gt;before()</code> or <code>$collection-&gt;after()</code> to insert sequenced tasks into the set of operations to be performed. One reason this might be done would be to define a base set of operations to perform (e.g. in a deploy), and then apply modifications for other environments (e.g. dev or stage).</p><div class="language-php line-numbers-mode" data-ext="php" data-title="php"><pre class="language-php"><code><span class="token php language-php"><span class="token delimiter important">&lt;?php</span>
  <span class="token variable">$collection</span><span class="token operator">-&gt;</span><span class="token function">addCode</span><span class="token punctuation">(</span>
    <span class="token keyword">function</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token keyword">use</span> <span class="token punctuation">(</span><span class="token variable">$work</span><span class="token punctuation">)</span>
    <span class="token punctuation">{</span>
      <span class="token comment">// do something with $work      </span>
    <span class="token punctuation">}</span><span class="token punctuation">,</span>
    <span class="token string double-quoted-string">&quot;taskname&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token delimiter important">?&gt;</span></span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Given a collection with named tasks, it is possible to insert more tasks before or after a task of a given name.</p><div class="language-php line-numbers-mode" data-ext="php" data-title="php"><pre class="language-php"><code><span class="token php language-php"><span class="token delimiter important">&lt;?php</span>
  <span class="token variable">$collection</span><span class="token operator">-&gt;</span><span class="token function">after</span><span class="token punctuation">(</span><span class="token string double-quoted-string">&quot;taskname&quot;</span><span class="token punctuation">,</span>
    <span class="token keyword">function</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token keyword">use</span> <span class="token punctuation">(</span><span class="token variable">$work</span><span class="token punctuation">)</span>
    <span class="token punctuation">{</span>
      <span class="token comment">// do something with $work after &quot;taskname&quot; executes, if it succeeds.    </span>
    <span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token delimiter important">?&gt;</span></span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><div class="language-php line-numbers-mode" data-ext="php" data-title="php"><pre class="language-php"><code><span class="token php language-php"><span class="token delimiter important">&lt;?php</span>
  <span class="token variable">$collection</span><span class="token operator">-&gt;</span><span class="token function">before</span><span class="token punctuation">(</span><span class="token string double-quoted-string">&quot;taskname&quot;</span><span class="token punctuation">,</span>
    <span class="token keyword">function</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token keyword">use</span> <span class="token punctuation">(</span><span class="token variable">$work</span><span class="token punctuation">)</span>
    <span class="token punctuation">{</span>
      <span class="token comment">// do something with $work before &quot;taskname&quot; executes.    </span>
    <span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token delimiter important">?&gt;</span></span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>It is recommended that named tasks be avoided unless specifically needed.</p>`,83),p=[o];function l(i,c){return s(),a("div",null,p)}const d=n(t,[["render",l],["__file","collections.html.vue"]]),u=JSON.parse('{"path":"/docs/collections.html","title":"Collection Builders","lang":"en-US","frontmatter":{},"headers":[{"level":2,"title":"Collections API","slug":"collections-api","link":"#collections-api","children":[{"level":3,"title":"TaskInterface Objects","slug":"taskinterface-objects","link":"#taskinterface-objects","children":[]},{"level":3,"title":"Functions","slug":"functions","link":"#functions","children":[]},{"level":3,"title":"Closures","slug":"closures","link":"#closures","children":[]},{"level":3,"title":"Methods","slug":"methods","link":"#methods","children":[]}]},{"level":2,"title":"Using a Collection Builder","slug":"using-a-collection-builder","link":"#using-a-collection-builder","children":[]},{"level":2,"title":"Rollbacks and Completions","slug":"rollbacks-and-completions","link":"#rollbacks-and-completions","children":[{"level":3,"title":"Completion Tasks","slug":"completion-tasks","link":"#completion-tasks","children":[]},{"level":3,"title":"Rollback Tasks","slug":"rollback-tasks","link":"#rollback-tasks","children":[]},{"level":3,"title":"Rollback and Completion Methods","slug":"rollback-and-completion-methods","link":"#rollback-and-completion-methods","children":[]},{"level":3,"title":"Rollback and Completion Callbacks","slug":"rollback-and-completion-callbacks","link":"#rollback-and-completion-callbacks","children":[]}]},{"level":2,"title":"Temporary Objects","slug":"temporary-objects","link":"#temporary-objects","children":[{"level":3,"title":"Temporary Directories","slug":"temporary-directories","link":"#temporary-directories","children":[]},{"level":3,"title":"Temporary Files","slug":"temporary-files","link":"#temporary-files","children":[]},{"level":3,"title":"The Temporary Global Collection","slug":"the-temporary-global-collection","link":"#the-temporary-global-collection","children":[]}]},{"level":2,"title":"Chained State","slug":"chained-state","link":"#chained-state","children":[{"level":3,"title":"Implicitly Passing State","slug":"implicitly-passing-state","link":"#implicitly-passing-state","children":[]},{"level":3,"title":"Explicitly Passing State","slug":"explicitly-passing-state","link":"#explicitly-passing-state","children":[]}]},{"level":2,"title":"Named Tasks","slug":"named-tasks","link":"#named-tasks","children":[]}],"git":{"updatedTime":1709072981000},"filePathRelative":"docs/collections.md"}');export{d as comp,u as data};
